public void decode(int[] received, int twoS) throws ReedSolomonException {
    GenericGFPoly poly = new GenericGFPoly(field, received);
    if (isNoError(poly, twoS)) {
        return;
    }
    GenericGFPoly syndrome = calculateSyndrome(poly, twoS);
    GenericGFPoly[] sigmaOmega = runEuclideanAlgorithm(syndrome, twoS);
    int[] errorLocations = findErrorLocations(sigmaOmega[0]);
    int[] errorMagnitudes = findErrorMagnitudes(sigmaOmega[1], errorLocations);
    correctErrors(received, errorLocations, errorMagnitudes);
}

private boolean isNoError(GenericGFPoly poly, int twoS) {
    for (int i = 0; i < twoS; i++) {
        if (poly.evaluateAt(field.exp(i + field.getGeneratorBase())) != 0) {
            return false;
        }
    }
    return true;
}

private GenericGFPoly calculateSyndrome(GenericGFPoly poly, int twoS) {
    int[] syndromeCoefficients = new int[twoS];
    for (int i = 0; i < twoS; i++) {
        syndromeCoefficients[syndromeCoefficients.length - 1 - i] = poly.evaluateAt(field.exp(i + field.getGeneratorBase()));
    }
    return new GenericGFPoly(field, syndromeCoefficients);
}

private GenericGFPoly[] runEuclideanAlgorithm(GenericGFPoly syndrome, int twoS) throws ReedSolomonException {
    if (syndrome.isZero()) {
        throw new ReedSolomonException("Syndrome is zero");
    }
    GenericGFPoly rLast = syndrome;
    GenericGFPoly tLast = field.getZero();
    GenericGFPoly t = field.getOne();

    while (2 * rLast.getDegree() >= twoS) {
        GenericGFPoly rLastLast = rLast;
        GenericGFPoly q = field.getZero();
        int denominatorLeadingTerm = rLast.getCoefficient(rLast.getDegree());
        int dltInverse = field.inverse(denominatorLeadingTerm);
        while (rLast.getDegree() >= rLastLast.getDegree() && !rLast.isZero()) {
            int degreeDiff = rLast.getDegree() - rLastLast.getDegree();
            int scale = field.multiply(rLast.getCoefficient(rLast.getDegree()), dltInverse);
            q = q.addOrSubtract(field.buildMonomial(degreeDiff, scale));
            rLast = rLast.addOrSubtract(rLastLast.multiplyByMonomial(degreeDiff, scale));
        }
        t = q.multiply(t).addOrSubtract(tLast);
    }

    int sigmaTildeAtZero = t.getCoefficient(0);
    if (sigmaTildeAtZero == 0) {
        throw new ReedSolomonException("sigmaTilde(0) was zero");
    }

    int inverse = field.inverse(sigmaTildeAtZero);
    GenericGFPoly sigma = t.multiply(inverse);
    GenericGFPoly omega = syndrome.multiply(inverse);
    return new GenericGFPoly[]{sigma, omega};
}

private int[] findErrorLocations(GenericGFPoly errorLocator) throws ReedSolomonException {
    int numErrors = errorLocator.getDegree();
    if (numErrors == 1) { // shortcut
        return new int[] { errorLocator.getCoefficient(1) };
    }
    int[] result = new int[numErrors];
    int e = 0;
    for (int i = 1; i < field.getSize() && e < numErrors; i++) {
        if (errorLocator.evaluateAt(i) == 0) {
            result[e] = field.inverse(i);
            e++;
        }
    }
    if (e != numErrors) {
        throw new ReedSolomonException("Error locator degree does not match number of roots");
    }
    return result;
}

private int[] findErrorMagnitudes(GenericGFPoly errorEvaluator, int[] errorLocations) {
    int s = errorLocations.length;
    int[] result = new int[s];
    for (int i = 0; i < s; i++) {
        int xiInverse = field.inverse(errorLocations[i]);
        int denominator = 1;
        for (int j = 0; j < s; j++) {
            if (i != j) {
                denominator = field.multiply(denominator, GenericGF.addOrSubtract(1, field.multiply(errorLocations[j], xiInverse)));
            }
        }
        result[i] = field.multiply(errorEvaluator.evaluateAt(xiInverse), field.inverse(denominator));
    }
    return result;
}

private void correctErrors(int[] received, int[] errorLocations, int[] errorMagnitudes) {
    for (int i = 0; i < errorLocations.length; i++) {
        int position = field.log(errorLocations[i]);
        if (position < 0 || position >= received.length) {
            throw new ReedSolomonException("Bad error location");
        }
        received[received.length - 1 - position] = GenericGF.addOrSubtract(received[received.length - 1 - position], errorMagnitudes[i]);
    }
}
