case BYTE_COMPACTION_MODE_LATCH:case BYTE_COMPACTION_MODE_LATCH_6:codeIndex=byteCompaction(code,codewords,encoding,codeIndex,result);
break;
case MODE_SHIFT_TO_BYTE_COMPACTION_MODE:result.append((char)codewords[codeIndex++]);
break;
case NUMERIC_COMPACTION_MODE_LATCH:codeIndex=numericCompaction(codewords,codeIndex,result);
break;
case ECI_CHARSET:encoding=getECICharset(codewords[codeIndex++]);
break;
case ECI_GENERAL_PURPOSE:codeIndex+=2;
break;
case ECI_USER_DEFINED:codeIndex++;
