    Random random = new Random(0);
    int minLength = 0;
    int utfLength = 0;
    for (int i = 0; i < 1000; i++) {
        String s = generateText(random, 100, chars, weights);
        minLength += encodeDecode(s, null, true, false);
        // TODO: Use this instead when the decoder supports multi ECI input
