int codeIndex=textCompaction(codewords,1,result);
PDF417ResultMetadata resultMetadata=new PDF417ResultMetadata();
while(codeIndex < codewords[0]){int code=codewords[codeIndex++];
switch(code)case TEXT_COMPACTION_MODE_LATCH:codeIndex=textCompaction(codewords,codeIndex,result);
break;
case BYTE_COMPACTION_MODE_LATCH:case BYTE_COMPACTION_MODE_LATCH_6:codeIndex=byteCompaction(code,codewords,encoding,codeIndex,result);
