    for (int i = 0; i < expectedLengths.length; i++) {
      StringBuilder sb = new StringBuilder();
      for (int j = 0; j <= i; j++) {
        sb.append(c);
      }
      encodeDecode(sb.toString(), expectedLengths[i]);
    }
  }

